parameters.jsCode:
const form = $input.first().json;

const faq = {
    "metadata":  {
                     "version":  "1.0",
                     "company":  "UrbanStyle.ltd",
                     "language":  "et",
                     "total_questions":  30,
                     "usage":  "n8n workflow teadmusbaas, Telegram bot, API",
                     "last_updated":  "2026-04-04",
                     "author":  "02Signal / Ettevõtluskeskus OÜ"
                 },
    "categories":  [
                       {
                           "name":  "Üldinfo",
                           "questions":  [
                                             {
                                                 "id":  1,
                                                 "question":  "Mis on UrbanStyle?",
                                                 "answer":  "UrbanStyle.ltd on 2020. aastal asutatud Eesti moe- ja jaekaubandusettevõte. Müüme kaasaegset urban-stiilis riietust nii e-poes urbanstyle.ee kui ka neljas füüsilises kaupluses üle Eesti. Meie fookuses on kvaliteetne, jätkusuutlik mood noortele linnainimestele."
                                             },
                                             {
                                                 "id":  2,
                                                 "question":  "Kus asuvad UrbanStyle\u0027i kauplused?",
                                                 "answer":  "Meil on neli kauplust: Tallinna Rotermanni kvartal (flagship, 120 m²), Tartu Tasku keskus (80 m²), Pärnu Port Artur (70 m²) ja Narva Fama keskus (65 m², avatud 2025). Lisaks töötab 24/7 e-pood urbanstyle.ee."
                                             },
                                             {
                                                 "id":  3,
                                                 "question":  "Millal UrbanStyle asutati ja kes on asutaja?",
                                                 "answer":  "UrbanStyle asutati 2020. aastal Kristi Tamme poolt. Ettevõte alustas ühe poega Tallinnas ja e-poega. Tänaseks on meil ~55 töötajat ja ~4 miljonit eurot aastakäivet."
                                             },
                                             {
                                                 "id":  4,
                                                 "question":  "Mis on UrbanStyle\u0027i missioon?",
                                                 "answer":  "Meie missioon on tuua Eesti turule kvaliteetset ja jätkusuutlikku moodi taskukohase hinnaga. Usume, et hea stiil ja vastutustundlik tarbimine käivad käsikäes."
                                             },
                                             {
                                                 "id":  5,
                                                 "question":  "Kes on UrbanStyle\u0027i sihtgrupp?",
                                                 "answer":  "Meie peamine sihtgrupp on 18-35-aastased linnaelanikud, kes väärtustavad kvaliteeti, stiili ja jätkusuutlikkust. Meie klient on teadlik tarbija, kes eelistab \"slow fashion\" lähenemist."
                                             }
                                         ]
                       },
                       {
                           "name":  "Tooted ja hinnad",
                           "questions":  [
                                             {
                                                 "id":  6,
                                                 "question":  "Milliseid tooteid UrbanStyle müüb?",
                                                 "answer":  "Müüme naiste riideid (~55% valikust), meeste riideid (~20%, kiiresti kasvav kategooria) ja aksessuaare (~25%). Meie kataloogis on ~350 toodet — riietest kottideni ja ehteteni."
                                             },
                                             {
                                                 "id":  7,
                                                 "question":  "Kas teil on Eesti disainerite tooteid?",
                                                 "answer":  "Jah! Umbes 30% meie toodangutest on Eesti disainerite loomingut. Ülejäänud 70% tuleb sertifitseeritud Euroopa tarnijatelt, peamiselt Skandinaaviast ja Baltimaadest."
                                             },
                                             {
                                                 "id":  8,
                                                 "question":  "Milline on UrbanStyle\u0027i hinnatase?",
                                                 "answer":  "Meie hinnad on keskklassis — kvaliteetsed tooted mõistliku hinnaga. Keskmine toote hind on 45-85 EUR. Hooajalised allahindlused on kuni -50%, lojaalsusprogrammi liikmed saavad lisasoodustusi."
                                             },
                                             {
                                                 "id":  9,
                                                 "question":  "Kuidas leida oma suurust?",
                                                 "answer":  "Iga toote lehel urbanstyle.ee-s on suurustetabel. Kui oled kahe suuruse vahel, soovitame valida suurem number. Meie kauplustes saad alati proovida — müüjad aitavad hea meelega sobiva suuruse leida."
                                             },
                                             {
                                                 "id":  10,
                                                 "question":  "Kas tooted on kvaliteetsed ja vastupidavad?",
                                                 "answer":  "Meie tooted on valitud hoolikalt — töötame ainult sertifitseeritud tarnijatega, kes kasutavad kvaliteetseid materjale. Orgaanilised ja taaskasutatud materjalid moodustavad kasvava osa meie valikust."
                                             }
                                         ]
                       },
                       {
                           "name":  "Tellimused ja tarne",
                           "questions":  [
                                             {
                                                 "id":  11,
                                                 "question":  "Kuidas tellida e-poest?",
                                                 "answer":  "Mine urbanstyle.ee, lisa tooted ostukorvi ja vormista tellimus. Aktsepteerime pangalinki, kaarditehinguid ja Montonio järelmaksu. Tellimuse kinnitus tuleb e-mailile kohe."
                                             },
                                             {
                                                 "id":  12,
                                                 "question":  "Kui kiiresti tellimus kohale jõuab?",
                                                 "answer":  "Tallinna ja Tartusse 1-2 tööpäeva, mujale Eestisse 2-3 tööpäeva. Paki saad kätte SmartPOST, Omniva või DPD pakiautomaadist. Kullertarne on saadaval Tallinnas ja Tartus."
                                             },
                                             {
                                                 "id":  13,
                                                 "question":  "Kas tarne on tasuta?",
                                                 "answer":  "Tarne on tasuta tellimustele alates 60 EUR. Alla selle on tarnekuluks 3.90 EUR pakiautomaadiga ja 5.90 EUR kulleriga. Lojaalsusprogrammi liikmetele on tarne alati tasuta."
                                             },
                                             {
                                                 "id":  14,
                                                 "question":  "Kas saab tellida ka väljaspoole Eestit?",
                                                 "answer":  "Jah, tarnime üle Baltikumi — Lätti ja Leetu. Tarneaeg on 3-5 tööpäeva, tarnekulu sõltub sihtkohast (tavaliselt 5-9 EUR). Tulevikus plaanime laieneda ka Soome turule."
                                             },
                                             {
                                                 "id":  15,
                                                 "question":  "Kuidas jälgida oma tellimust?",
                                                 "answer":  "Pärast saatmist saad e-mailiga jälgimiskoodi. Selle abil näed reaalajas, kus su pakk on. Kui jälgimiskood ei tööta, kirjuta meile info@urbanstyle.ee."
                                             }
                                         ]
                       },
                       {
                           "name":  "Tagastused ja vahetused",
                           "questions":  [
                                             {
                                                 "id":  16,
                                                 "question":  "Milline on tagastuspoliitika?",
                                                 "answer":  "Sul on 30 päeva alates kättesaamisest toote tagastamiseks. Toode peab olema kasutamata, originaalpakendis ja siltidega. Tagastus on tasuta — kasuta kaasas olevat tagastussilti."
                                             },
                                             {
                                                 "id":  17,
                                                 "question":  "Kuidas vahetada toodet teise suuruse vastu?",
                                                 "answer":  "Saada meile e-mail aadressile info@urbanstyle.ee soovitud suurusega. Me saadame uue toote kohe, kui vana on teel tagasi. Vahetamine on tasuta."
                                             },
                                             {
                                                 "id":  18,
                                                 "question":  "Kui kiiresti raha tagasi saab?",
                                                 "answer":  "Tagasimakse töödeldakse 3-5 tööpäeva jooksul pärast tagastatud toote kättesaamist. Raha laekub samale makseviisile, millega tellimus tehti."
                                             },
                                             {
                                                 "id":  19,
                                                 "question":  "Kas saab tagastada allahindlusega ostetud tooteid?",
                                                 "answer":  "Jah, allahindlusega ostetud tooteid saab tagastada tavatingimustel. Tagastatakse tegelik makstud summa. Ainus erand: personaliseeritud või graveeritud aksessuaarid."
                                             }
                                         ]
                       },
                       {
                           "name":  "Lojaalsusprogramm",
                           "questions":  [
                                             {
                                                 "id":  20,
                                                 "question":  "Mis on UrbanStyle\u0027i lojaalsusprogramm?",
                                                 "answer":  "Meie lojaalsusprogramm \"UrbanStyle Club\" on tasuta liikmelisusega. Liikmed saavad: tasuta tarne, -10% esimeselt ostult, sünnipaevapakkumine, varajane ligipääs uutele kollektsioonidele ja eksklusiivne allahindlus."
                                             },
                                             {
                                                 "id":  21,
                                                 "question":  "Kuidas liituda lojaalsusprogrammiga?",
                                                 "answer":  "Liitu veebis urbanstyle.ee/club, kaupluses kassas või tellimuse vormistamisel. Vajad ainult e-maili aadressi. Praegu on meil ~1200 aktiivset liiget."
                                             },
                                             {
                                                 "id":  22,
                                                 "question":  "Milliseid soodustusi liikmed saavad?",
                                                 "answer":  "Iga ostu eest kogunevad punktid (1 EUR = 1 punkt). 100 punkti = 5 EUR soodustus. Lisaks: tasuta tarne, varajased juurdepääsud ja sünnipaevapakkumine (-20%)."
                                             }
                                         ]
                       },
                       {
                           "name":  "Jätkusuutlikkus",
                           "questions":  [
                                             {
                                                 "id":  23,
                                                 "question":  "Kuidas UrbanStyle jätkusuutlikkust toetab?",
                                                 "answer":  "Jätkusuutlikkus on meie põhiväärtus. Töötame ainult sertifitseeritud tarnijatega, kasutame orgaanilisi ja taaskasutatud materjale ning toetame \"slow fashion\" lähenemist — kvaliteet üle kvantiteedi."
                                             },
                                             {
                                                 "id":  24,
                                                 "question":  "Mis on ringlussevõtu programm?",
                                                 "answer":  "Too vana riideese ükskõik millisesse meie kauplusesse ja saa -10% allahindlus järgmiselt ostult. Kogutud rõivad suunatakse taaskasutusse koostöös Eesti heategevusorganisatsioonidega."
                                             },
                                             {
                                                 "id":  25,
                                                 "question":  "Kas UrbanStyle toetab kogukonda?",
                                                 "answer":  "Jah! 1% meie käibest läheb Eesti looduskaitse organisatsioonidele. Lisaks toetame kohalikke disainereid ja noori moeloojaid oma platvormiga."
                                             }
                                         ]
                       },
                       {
                           "name":  "Klienditeenindus",
                           "questions":  [
                                             {
                                                 "id":  26,
                                                 "question":  "Kuidas UrbanStyle\u0027iga ühendust võtta?",
                                                 "answer":  "E-mail: info@urbanstyle.ee (vastame 24h jooksul). Telefon: +372 5XX XXXX (E-R 9-18). Instagram DM: @urbanstyle.ee. Kaupluses: meie müüjad aitavad hea meelega."
                                             },
                                             {
                                                 "id":  27,
                                                 "question":  "Millal on kauplused avatud?",
                                                 "answer":  "Kõik kauplused on avatud E-L 10:00-20:00 ja P 11:00-18:00. Riigipühadel võivad lahtiolekuajad erineda — vaata urbanstyle.ee/kauplused."
                                             },
                                             {
                                                 "id":  28,
                                                 "question":  "Kuidas esitada kaebust?",
                                                 "answer":  "Kirjuta meile info@urbanstyle.ee märksõnaga \"Kaebus\" või helista. Iga kaebus vaadatakse üle 48 tunni jooksul. Meie eesmärk on leida lahendus, millega oled rahul."
                                             }
                                         ]
                       },
                       {
                           "name":  "E-pood",
                           "questions":  [
                                             {
                                                 "id":  29,
                                                 "question":  "Kas e-pood on turvaline?",
                                                 "answer":  "Jah, urbanstyle.ee kasutab SSL-krüpteeringut ja kõik maksed töödeldakse läbi turvaliste makseteenuse pakkujate (Montonio, Stripe). Me ei salvesta su kaardiandmeid."
                                             },
                                             {
                                                 "id":  30,
                                                 "question":  "Kas saab maksta järelmaksuga?",
                                                 "answer":  "Jah, pakume Montonio järelmaksu — jaota makse 3-12 kuu peale. Järelmaks on kättesaadav tellimustele alates 30 EUR. Tingimused ja intressimäärad kuvatakse tellimuse vormistamisel."
                                             }
                                         ]
                       }
                   ]
};

return [
  {
    json: {
      customerName: form['Kliendi nimi'] || '',
      customerCategory: form['Küsimuse kategooria'] || '',
      customerQuestion: form['Küsimus'] || '',
      faq
    }
  }
];

parameters.text:
=Klient täitis päringu vormi. Koosta Telegrami saadetav lühike ja viisakas eestikeelne vastus FAQ andmete põhjal. Eelista vastamisel kliendi valitud kategooriat, aga vajadusel kasuta ka muud FAQ infot. Kui FAQ ei sisalda piisavat infot, ütle ausalt, et küsimus vajab käsitsi ülevaatamist, ning lisa lühike soovitus järgmise sammu kohta.

Kliendi nimi: {{$json.customerName}}
Küsimuse kategooria: {{$json.customerCategory}}
Kliendi küsimus: {{$json.customerQuestion}}

FAQ JSON:
{{ JSON.stringify($json.faq, null, 2) }}

Väljund peab olema ainult Telegrami sõnumi tekst. Ära lisa markdown tabelit ega tehnilist selgitust.

=📩 Uus kliendi päring

Nimi: {{$node["FAQ JSON"].json.customerName}}
Kategooria: {{$node["FAQ JSON"].json.customerCategory}}
Küsimus: {{$node["FAQ JSON"].json.customerQuestion}}

AI vastus:
{{$json.output}}
